export default async function () {
  const form = new FormData();

  form.append('request', JSON.stringify({
    filePath: '/lookups/CA/userdata',   //please use this path to match the dashboard requirements
    parsePattern: `JSON:json`,   
    overwrite: true,
    lookupField: 'user.email'  
  }));

// your custom JSON goes here - as shown in the example
const jsonContent = `[
{"user.email":"abc@de.fg",
    "user.id":"00000000-0000-0000-0000-000000000000",
    "dt.cost.costcenter":"a",
    "dt.cost.product":"1"}
  ]`;
const jsonBlob = new Blob([jsonContent], { type: 'application/json' });
form.append('content', jsonBlob, 'content.json');

  const response = await fetch('/platform/storage/resource-store/v1/files/tabular/lookup:upload', {
    method: 'POST',
    body: form,
    // No headers needed — fetch will set them correctly
  });

  if (!response.ok) {
    const errorText = await response.text();
    return 'Upload failed: ' + errorText;
  } else {
    const result = await response.text();
    return 'Upload successful';
  }
}

